// INPUT VALIDATION & SANITIZATION
const callData = items[0].json;

// Required fields validation
const requiredFields = ['client_id', 'call_id', 'transcript'];
const missingFields = requiredFields.filter(field => !callData[field]);

if (missingFields.length > 0) {
  throw new Error(`Missing required fields: ${missingFields.join(', ')}`);
}

// Sanitize and validate data
const sanitizedData = {
  client_id: String(callData.client_id).trim() || 'unknown',
  call_id: String(callData.call_id).trim(),
  transcript: String(callData.transcript).trim(),
  user_intent: String(callData.intent || '').toLowerCase().trim(),
  lead_info: {
    name: String(callData.lead_name || '').trim(),
    phone: String(callData.lead_phone || '').replace(/[^0-9+]/g, ''),
    email: String(callData.lead_email || '').toLowerCase().trim()
  },
  metadata: {
    call_duration: parseInt(callData.duration) || 0,
    timestamp: new Date().toISOString(),
    language: String(callData.language || 'en').toLowerCase(),
    received_at: new Date().toISOString()
  },
  // Original payload for debugging
  _original: callData
};

// Email validation (if provided)
if (sanitizedData.lead_info.email && !sanitizedData.lead_info.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) {
  sanitizedData.lead_info.email = ''; // Invalid email, clear it
}

console.log(`[VALIDATION] Call ${sanitizedData.call_id} validated successfully`);

return [{ json: sanitizedData }];

// STRUCTURED DATA TRANSFORMATION
const callData = items[0].json;

// Enhanced structured data with analytics flags
const structuredData = {
  ...callData,
  // Add processing flags
  processing: {
    validated: true,
    timestamp: new Date().toISOString(),
    version: '2.0'
  },
  // Intent analysis flags
  flags: {
    is_booking: /booking|reservation|schedule|appointment/i.test(callData.user_intent),
    has_contact: !!(callData.lead_info.phone || callData.lead_info.email),
    is_qualified: !!(callData.lead_info.name && (callData.lead_info.phone || callData.lead_info.email)),
    has_questions: (callData.transcript.match(/\?/g) || []).length > 0
  }
};

console.log(`[TRANSFORM] Call ${structuredData.call_id} - Booking: ${structuredData.flags.is_booking}, Qualified: ${structuredData.flags.is_qualified}`);

return [{ json: structuredData }];

// CRM ERROR HANDLER
const item = items[0];

if (item.error) {
  const errorData = {
    call_id: item.json.call_id,
    client_id: item.json.client_id,
    error: {
      message: item.error.message || 'Unknown error',
      type: 'CRM_API_FAILURE',
      timestamp: new Date().toISOString(),
      retry_count: item.json.retry_count || 0
    },
    // Keep original data for retry queue
    original_data: item.json
  };

  console.error(`[CRM ERROR] Call ${errorData.call_id}: ${errorData.error.message}`);

  // TODO: Send to error queue / dead letter queue
  return [{ json: errorData }];
}

// Success path
const successData = {
  ...item.json,
  crm_response: {
    success: true,
    sent_at: new Date().toISOString(),
    response: item.json
  }
};

console.log(`[CRM SUCCESS] Call ${successData.call_id} sent to CRM`);

return [{ json: successData }];

// MERGE: Combine CRM path and non-booking path
const allItems = $input.all();

// Get the most recent/complete data
const mergedData = allItems.reduce((acc, item) => {
  return { ...acc, ...item.json };
}, {});

console.log(`[MERGE] Processing analytics for call ${mergedData.call_id}`);

return [{ json: mergedData }];

// LIGHTRAG DATA PREPARATION
const callData = items[0].json;

const ragData = {
  client_id: callData.client_id,
  call_id: callData.call_id,
  timestamp: callData.metadata.timestamp,

  // Enhanced content with structure
  content: `### Call Transcript\n${callData.transcript}\n\n` +
           `### Intent Analysis\nUser Intent: ${callData.user_intent}\n` +
           `Booking Intent: ${callData.flags?.is_booking ? 'Yes' : 'No'}\n` +
           `Lead Qualified: ${callData.flags?.is_qualified ? 'Yes' : 'No'}\n\n` +
           `### Lead Information\n` +
           `Name: ${callData.lead_info.name || 'Not provided'}\n` +
           `Phone: ${callData.lead_info.phone || 'Not provided'}\n` +
           `Email: ${callData.lead_info.email || 'Not provided'}\n\n` +
           `### Call Metadata\n` +
           `Duration: ${callData.metadata.call_duration} seconds\n` +
           `Language: ${callData.metadata.language}`,

  // Enhanced tags
  tags: [
    `client:${callData.client_id}`,
    `intent:${callData.user_intent}`,
    `booking:${callData.flags?.is_booking}`,
    `qualified:${callData.flags?.is_qualified}`,
    `duration:${callData.metadata.call_duration}`,
    `language:${callData.metadata.language}`,
    `year:${new Date().getFullYear()}`,
    `month:${new Date().getMonth() + 1}`
  ],

  // Enhanced analytics
  analytics: {
    common_questions: (callData.transcript.match(/\?/g) || []).length,
    lead_qualified: callData.flags?.is_qualified || false,
    intent_category: callData.user_intent,
    booking_intent: callData.flags?.is_booking || false,
    has_contact_info: callData.flags?.has_contact || false,
    crm_sent: !!callData.crm_response,
    call_duration_minutes: Math.round(callData.metadata.call_duration / 60)
  }
};

console.log(`[RAG PREP] Prepared analytics data for call ${ragData.call_id}`);

return [{ json: ragData }];

// LIGHTRAG ERROR HANDLER
const item = items[0];

if (item.error) {
  console.error(`[RAG ERROR] Call ${item.json.call_id}: ${item.error.message}`);

  // Continue with degraded service
  return [{ 
    json: {
      ...item.json,
      rag_status: 'failed',
      rag_error: item.error.message
    }
  }];
}

// Success
console.log(`[RAG SUCCESS] Call ${item.json.call_id} stored in LightRAG`);

return [{ 
  json: {
    ...item.json,
    rag_status: 'success',
    rag_stored_at: new Date().toISOString()
  }
}];

// MERGE: Combine all execution paths for final response
const allItems = $input.all();

// Combine all data
const finalData = allItems.reduce((acc, item) => {
  return { ...acc, ...item.json };
}, {});

// Build response summary
const response = {
  success: true,
  message: 'Call processed successfully',
  call_id: finalData.call_id,
  client_id: finalData.client_id,
  processing: {
    validated: true,
    crm_sent: !!finalData.crm_response,
    crm_status: finalData.crm_response?.success ? 'success' : (finalData.error?.type === 'CRM_API_FAILURE' ? 'failed' : 'skipped'),
    rag_stored: finalData.rag_status === 'success',
    rag_status: finalData.rag_status || 'unknown',
    completed_at: new Date().toISOString()
  },
  flags: finalData.flags,
  // Errors if any
  errors: [
    finalData.error && { type: 'crm', message: finalData.error.message },
    finalData.rag_error && { type: 'rag', message: finalData.rag_error }
  ].filter(Boolean)
};

console.log(`[FINAL] Call ${response.call_id} processed - CRM: ${response.processing.crm_status}, RAG: ${response.processing.rag_status}`);

return [{ json: response }];
